const Q_CHEMISTRY_2007=[{"id": "objective>Chemistry>2007>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many structural isomers of chlorobutane are possible?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorobutane <br/> The molecular formula is C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">9</span>cl <br/>  <br/>  <br/> It implies that chlorobutane has 4 structural isomers <br/> The 4 structural isomes includes ,1-chlorobutane, 2-chlorobutane,1chloro, 2-mehylpropane  and 2-chloro2-methylporpane  </div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2007>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The conversion of open chain alkanes into cycloalkanes and aromatic compounds is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reforming </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cracking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isomerization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">polymerization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Reforming is a process in the oil industry where the structure of hydrocarbon molecules is rearranged to produce higher-value molecules. This can involve the conversion of straight-chain alkanes into branched-chain isomers, cycloalkanes, or aromatic compounds.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2007>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following represents an aromatic compound?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">9</span>OH </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An aromatic compound is a cyclic, planar compound with delocalized π electrons above and below the plane of the molecule. The most common example is benzene, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>. C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH, also known as phenol, is an aromatic compound because it has a benzene ring.</div>", "topic": "ORGANIC COMPOUNDS : AROMATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2007>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Certain useful waxes are composed mainly of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amino acids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanoates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glycerols </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanols</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Waxes are typically esters of long-chain fatty acids (alkanoates) with long-chain alcohols. Esters are also known as alkanoates and have the general formula of RCOOR</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2007>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following alkanes has the highest boiling point?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Propane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Methane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pentane</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The boiling point of alkanes increases with the increase in the number of carbon atoms. This is due to the increase in the size of the molecule and the strength of the London dispersion forces. Therefore, Pentane, which has five carbon atoms, has the highest boiling point among the given options.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2007>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC nomenclature of the compound CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>COOCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethyl propanoate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propyl ethanoate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethyl butanoate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">methyl butanoate</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC nomenclature of the compound CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>COOCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is ethyl propanoate. In IUPAC nomenclature, the name of an ester is derived from the names of the alcohol and the carboxylic acid from which it is formed. The alcohol part is named first (ethyl), and the acid part is named second (propanoate).</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2007>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds is the best possible anti-knock agent for petrol?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>C–CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH–CH(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)CHCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Anti-knock properties is increased with the presence of branched chain hydrocarbons.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2007>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cl + KCN → CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CN + KCl  <br/>  In the reaction above, the cyanide is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrophilic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrophilic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrophobic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleophilic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, cyanide (CN-) acts as a nucleophile. A nucleophile is a chemical species that donates an electron pair to an electrophile to form a chemical bond in a reaction. Cyanide, being a negatively charged ion, has a pair of electrons that it can donate, making it a nucleophile.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2007>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The hydrocarbon used in the production of styrene is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">propyne </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethyne</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Styrene is produced from the hydrocarbon ethene, also known as ethylene. Ethene is a simple alkene and is used in the production of polystyrene, a common plastic material, through a process called polymerization.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2007>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds is a tertiary alkanol?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The compound above conforms to the general structural formula of the tertiary alkanol.A tertiary alcohol can be identified by the presence of 3 alkyl groups attached to the carbon atom carrying the hydroxyl group.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2007>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the electron configuration of an element is 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>, how many unpaired electrons are there?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electron configuration 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> indicates that there is one unpaired electron in the 2p orbital. Electrons fill orbitals in a way that minimizes the energy of the atom, so the two 2s electrons are paired in the same orbital, and four of the 2p electrons are paired in two orbitals, leaving one electron unpaired in the third 2p orbital.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2007>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal X forms two bromides with the formulae XBr and XBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>. What type of <br/> bonding exists between X and bromine in the bromides?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dative bonding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metallic bonding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ionic bonding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Covalent bonding</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The metal X forms two different bromides, indicating that it can lose either one or three electrons to form positive ions. This is characteristic of ionic bonding, where electrons are transferred from one atom (in this case, the metal) to another (bromine) to form ions, which are then attracted to each other due to their opposite charges.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2007>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(S)</span> + xHCl(aq) → MnCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span> + yH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span>+ zCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/>  In the equation above, what are the values of x, y and z respectively?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4, 2, 1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 1, 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4, 1, 2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1, 2, 1</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Mn)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span> + xHcl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → Mncl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span> + yH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> + zcl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/> Balance out oxygen to determine \"y\" <br/> 2(0) = y(0) <br/> y = 2 <br/> Balance out hydrogen to determine \"x\" <br/> x(H) = y(2H) <br/> x = 2y <br/> since y = 2 <br/> x = 2(2) = 4 <br/> Balance out chlorine to determine \"z\" <br/> x(cl) = 2(cl) + z(2(cl)) <br/> x(cl) = 2(cl) + 2z(cl) <br/> x = 2 + 2z <br/> since x = 4 <br/> 4 = 2 + 2z <br/> 2z = 2 <br/> z = 1 <br/> (x, y, z) = (4, 2, 1)</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2007>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The elements that belong to the third period of the periodic table are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na, P, O and Cl </div>", "<div style=\"font-family:Cambria;font-size:17px;\">B, C, N and O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na, Mg, S and Ar </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Li, Be, Al and P</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Na => Sodium (Atomic number = 11; 2, 8, 1) <br/> Mg => Magnesium (Atomic number = 12; 2, 8, 2) <br/> S => Sulphur (Atomic number = 16; 2, 8, 6) <br/> Ar => Argon (Atomic number = 18; 2, 8, 8) <br/> As you can see the electrons are distributed into three (3) shells, therefore, they belong to period 3</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2007>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of petrol and water can be separated through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">centrifugation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of filter paper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of separating funnel</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of petrol and water can be separated through the use of a separating funnel. This is because petrol and water are immiscible liquids, meaning they do not mix. When poured into a separating funnel, they form two distinct layers due to their different densities. The tap of the funnel can then be opened to allow the denser liquid (water) to flow out, leaving the less dense liquid (petrol) in the funnel.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2007>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the mass of chlorine gas which occupies a volume of 1.12dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at s.t.p. <br/> [Cl = 35.5, Molar volume of a gas at s.t.p. = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.55g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.50g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.80g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.10g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mass of 1 mole of Cl2 gas = mole × molarmass <br/> But molarmass of Cl2 = 35.5 x 2 = 71g/ mol <br/> Therefore mass of 1 mole  chlorine gas = 1 × 71 <br/> = 71g <br/> But 1 mole of any gas at s.t.p occupies 22.4dm <br/> There 1 mole of Cl2 = 71g of chlorine occupies 22.4dm3 <br/> Xg of chlorine will occupy 1.12dm3 <br/>  <br/> X = 71g × 1.12dm3/22.4dm <br/> =  3.55g</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2007>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which experiment led to the measurement of the charge on an electron?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Discharge-tube experiment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Scattering α - particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mass spectrometric experiment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oil-drop experiment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oil-drop experiment led to the measurement of the charge on an electron. This experiment was conducted by Robert A. Millikan and Harvey Fletcher in 1909 to measure the elementary electric charge (the charge of the electron). The experiment involved observing tiny charged droplets of oil located between two horizontal metal electrodes. By manipulating the electric field between the electrodes, Millikan and Fletcher were able to measure the charge on an electron.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2007>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the volume of oxygen required to burn completely 45cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of methane at s.t.p.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">135.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">180.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">90.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">45.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>+ 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O  <br/>  The mole ratio of the reactants is 1:2  <br/>  From this, it can be deduced that 90cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is required to burn 45cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of methane. </div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2007>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many electrons are in the L shell of <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">31</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">15</span>P ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">18 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The L shell of an atom is the second energy level and can hold up to 8 electrons. The atomic number of phosphorus (P) is 15, which means it has 15 electrons. The first energy level (K shell) can hold up to 2 electrons, and the remaining 13 electrons will be distributed among the next energy levels. Therefore, the L shell of phosphorus will have 8 electrons.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2007>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following decreases when a given mass of a gas is compressed to half its initial volume?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Frequency of collisions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Number of molecules present</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Atomic radius of each particle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Average intermolecular distance</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a gas is compressed, the volume decreases. This means the particles are closer together, hence the average intermolecular distance decreases. The frequency of collisions increases due to the particles being closer together. The number of molecules present and the atomic radius of each particle remain the same as these are not affected by changes in volume.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2007>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(aq)</span> + 2HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 2NaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>+ H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O(l)+ SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(S)</span> <br/>  Which of the following would introduce the greatest increase in the rate of the chemical reaction above?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An increase in temperature and an increase in the concentration of the reactants.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in volume and an increase in the pressure of the reactants.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in temperature and a decrease in the concentration of the reactants.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in temperature and an increase in the concentration of the reactants.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of a chemical reaction can be increased by increasing the temperature and the concentration of the reactants. Increasing the temperature provides the reactant particles with more kinetic energy, which increases the frequency of successful collisions. Increasing the concentration of the reactants increases the number of reactant particles per unit volume, which also increases the frequency of successful collisions.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2007>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An element used in the production of matches is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aluminium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur is used in the production of matches. When a match is struck, the friction generates enough heat to convert the red phosphorus on the matchbox to white phosphorus. This reacts with the potassium chlorate in the match head to produce enough heat to ignite the sulphur, which sustains the flame long enough to ignite the wood of the matchstick.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : SULPHUR"}, {"id": "objective>Chemistry>2007>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When calcium oxide is heated with carbon, the oxide will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">be converted to the trioxocarbonate(IV) salt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decompose to the metal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be converted to the carbide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">melt, producing carbon (IV) oxide</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When calcium oxide (CaO) is heated with carbon (C), the oxide is reduced to the metal and carbon monoxide is formed. This is a reduction reaction where carbon acts as a reducing agent, removing the oxygen from calcium oxide to form calcium carbide (CaC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>).</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALINE-EARTH METALS"}, {"id": "objective>Chemistry>2007>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The alternative raw material labelled M is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">steam </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural gas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The alternative raw material labelled M, is steam.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2007>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The fuel gas labelled L is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">water gas</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fuel gas labeled L in the diagram is water gas.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2007>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reddish-brown rust on iron roofing sheets consists of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span>(H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">FeO.H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>.2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reddish-brown rust on iron roofing sheets consists of hydrated iron(III) oxide, Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. This compound forms when iron reacts with oxygen in the presence of water or moisture.</div>", "topic": "ELECTROLYSIS : CORROSION"}, {"id": "objective>Chemistry>2007>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The tincture of iodine means iodine dissolved in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bromine chloride </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tincture of iodine is a solution of iodine in ethanol. It is used as a disinfectant for wounds.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2007>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A solution which on treatment with hydrochloric acid produces a colourless, odourless gas which turns lime water milky is most likely to be a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trioxocarbonate(IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trioxonitrate(V)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydroxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloride</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A solution of trioxocarbonate(IV) or carbonate reacts with hydrochloric acid to produce carbon dioxide, a colorless, odorless gas that turns lime water milky. </div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2007>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>PO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span>+ H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> ⇔  H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>PO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> ΔH = –13KJ at 298K  <br/>  In the reaction above, an increase in temperature would</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have no effect on the reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slow down the reverse reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">favour the forward reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">favour the reverse reaction</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction is exothermic as indicated by the negative ΔH. According to Le Chatelier's principle, an increase in temperature for an exothermic reaction shifts the equilibrium to the left, favoring the reverse reaction.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2007>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following sets of metals dissolves in dilute HCl?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mg, Sn and Fe </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg, Fe and Cu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe, Sn and Cu </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu, Mg and Sn</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium (Mg), Tin (Sn), and Iron (Fe) are all reactive metals that will dissolve in dilute hydrochloric acid to produce a metal chloride and hydrogen gas. Copper (Cu) is less reactive and will not react with dilute hydrochloric acid.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM~~METALS AND THEIR COMPOUNDS : COPPER~~METALS AND THEIR COMPOUNDS : IRON~~METALS AND THEIR COMPOUNDS : TIN"}, {"id": "objective>Chemistry>2007>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If chlorine is bubbled into water and the resulting yellowish-green solution is exposed to bright sunlight for a while,the solution will decompose giving out</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oxygen, thereby producing hypochlorous acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine and oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen and leaving behind aqueous hydrochloric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen, hydrogen and chlorine</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When chlorine is bubbled into water, it forms a mixture of hydrochloric acid and hypochlorous acid. If this solution is exposed to sunlight, it decomposes to form oxygen and hydrochloric acid. </div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2007>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 4NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> ⇔  [Cu(NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>  <br/>  In the reaction above, what is the effect of precipitating Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> as CuS<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">More NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> will be generated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">There will be no effect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> concentration will decrease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium will shift to the right</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Le Chatelier's principle states that if a system at equilibrium is disturbed, it will adjust to minimize the disturbance and restore equilibrium. <br/>  <br/> When Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>  is precipitated as CuS<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>, the concentration of Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>  in the aqueous phase decreases.  <br/>  <br/> According to Le Chatelier's principle, the equilibrium will shift to counteract this change by producing more Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>  Therefore, the reaction will shift to the left to increase the Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> concentration, thus more NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> will be generated</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2007>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Copper and silver metals are commonly used as coins because they are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">easily oxidized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">not easily reduced</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not easily oxidized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">easily reduced</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Copper and silver are commonly used as coins because they are not easily oxidized. Oxidation is a process that involves the loss of electrons. If a metal is easily oxidized, it would react readily with substances in the environment (like oxygen and water), leading to corrosion or tarnishing. Since copper and silver are not easily oxidized, they do not corrode or tarnish easily, making them suitable for use as coins.</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2007>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, the respective activation energies for the catalyzed and uncatalyzed reactions in kJ are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">30 and 35 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">40 and 45</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50 and 45 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">45 and 50</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For the catalyzed reaction, the activation energy = 45-15= 30kJ  <br/>  For the uncatalyzed reaction, the activation energy = 50-15=35kJ</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2007>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The soft solder used for welding and plumbing is an alloy of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">iron and zinc </div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron and tin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead and tin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead and zinc</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soft solder, commonly used for welding and plumbing, is an alloy of lead and tin. An alloy is a mixture of two or more metals. The combination of lead and tin in soft solder provides a low melting point and good bonding properties, making it suitable for these applications.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2007>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A good drying agent should be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hygroscopic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deliquescent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">effervescent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">efflorescent</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A good drying agent should be hygroscopic i.e it must have the ability to absorb water without changing its nature.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2007>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A supersaturated solution is said to contain</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">more solute than it can dissolve at that temperature in the presence of undissolved solute</div>", "<div style=\"font-family:Cambria;font-size:17px;\">as much solute as it can dissolve at that temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more solute than it can dissolve at that temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">as much solute as it can dissolve at that temperature in the presence of undissolved solute</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A supersaturated solution is one that contains more of the solute than it can dissolve at that temperature.</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2007>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When temporary hard water is boiled for some time in a kettle, the inner surface of the kettle becomes coated with a deposit of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aluminium trioxocarbonate(IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium hydrogentrioxocarbonate(IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium tetraoxosulphate(VI)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium trioxocarbonate(IV)</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Boiling temporary hard water is boiled for some time in a kettle, the inner surface of the kettle becomes coated with a deposit of calcium trioxocarbonate (IV).</div>", "topic": "WATER : COMPOSITION BY VOLUME"}, {"id": "objective>Chemistry>2007>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What weight of NaCl is needed to make 2.0dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a 1.5M solution?  <br/>  [Na = 23, Cl = 35.5]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">175.5g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">116g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">87g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">58g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Molar mass of NaCl=23+35.5=58.5g/mol <br/> Concentration = no of moles/volume  <br/>  no of moles = 2 × 1.5 = 3 moles  <br/>  no of moles = mass/molar mass. Hence, mass = 58.5 × 3 = 175.5g</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2007>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Smog usually occurs over cities which</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have very few plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are surrounded by water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">burn a lot of fossil fuels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are overpopulated</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Smog is a type of air pollution that is a mixture of smoke and fog. It usually occurs over cities that burn a lot of fossil fuels, such as coal and gasoline, for heating, transportation, and industrial processes.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2007>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of nitrogen in air is to slow down</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">combustion and corrosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respiration and combustion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respiration and transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">corrosion and respiration</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen is a relatively inert gas that makes up about 78% of the Earth's atmosphere. Its presence in air slows down combustion (burning) and corrosion (oxidation) by diluting the oxygen and reducing its availability for these reactions.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2007>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation state of oxygen in tetraoxosulphate (VI) acid is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">–4 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">–8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+4 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">–2</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation state of oxygen in tetraoxosulphate (VI) acid is -2. <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>;  <br/> (1 x 2) + 6 + 4x = 0 <br/> 4x = -8,  <br/> x = - 2</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2007>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tartaric acid is used industrially to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remove rust</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make fruit juices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make baking powder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dry substances</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tartaric acid is used in the food industry as an essential ingredient in baking powder. It reacts with baking soda to produce carbon dioxide gas, which helps dough rise.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2007>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(g)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> →  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6(g)</span>    ΔH = –137kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">–1</span>  <br/>  The reaction represented above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">spontaneous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">in equilibrium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endothermic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exothermic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction is exothermic because it releases heat (ΔH is negative). An exothermic reaction is a chemical reaction that releases energy by light or heat. It is the opposite of an endothermic reaction.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2007>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How long would it take to deposit 0.08g of copper from CuCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> solution by passing a current of 0.5A?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8 mins </div>", "<div style=\"font-family:Cambria;font-size:17px;\">48 mins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6 mins </div>", "<div style=\"font-family:Cambria;font-size:17px;\">24 mins</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At the cathode <br/> Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> N.B: 1e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> = 96,500C <br/> 2(96,500C) deposits 64g of copper <br/> 193000C ≡ 64g <br/> x ≡ 0.08 <br/> 64x = 1930 × 8 <br/> 8x = 1930 <br/> x = 241.25C <br/> Recall: Q = It <br/> 241.25 = 0.5 × t <br/> t = 482.5 seconds <br/> convert this to minute <br/> 482.5 seconds ≡ 8 minutes</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2007>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the number of moles of HCl present in 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a 0.75M solution of <br/> the acid.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.500 moles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.015 mole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.800 moles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.038 mole</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Volume = 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.02dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Concentration = 0.75M <br/> Recall: No of moles = volume × concentration  <br/>  = 0.02 × 0.75 = 0.015 mole</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2007>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dissolving some pellets of NaOH in water would result in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the entropy of the solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the free energy of the solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a lowering of the temperature of the solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the entropy of the solution</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dissolving pellets of NaOH in water would result in an increase in the entropy of the solution. Entropy is a measure of the randomness or disorder of a system. When NaOH dissolves in water, the system becomes more disordered, hence the entropy increases.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2007>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction that takes place in a Daniel cell is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">neutralization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">double decomposition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct combination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">redox</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Daniel cell is a type of electrochemical cell where a redox reaction takes place. Redox is a type of chemical reaction where oxidation and reduction occur. Oxidation is the loss of electrons, while reduction is the gain of electrons.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>2007>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What happens when zinc rod is immersed in copper(II)tetraoxosulphate(VI) solution?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The copper generates more copper ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electrons flow from copper to zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The blue colour of the solution disappears</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The zinc rod remains undissolved</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a zinc rod is immersed in a copper(II)tetraoxosulphate(VI) solution, a displacement reaction occurs. The zinc displaces the copper ions in the solution, forming zinc sulphate and copper. This causes the blue colour of the copper(II)tetraoxosulphate(VI) solution to disappear as the copper ions are reduced to copper metal.</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2007>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The salt formed from a strong acid and a strong base is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">neutral </div>", "<div style=\"font-family:Cambria;font-size:17px;\">complex </div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">basic</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A salt formed from a strong acid and a strong base is neutral. This is because the strong acid and strong base neutralize each other's effects, resulting in a salt that has a neutral pH.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}];
